import { useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import usePageTitle from '../hooks/usePageTitle';

const S = {
  page: {
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    background: '#0D1117',
    color: '#E6EDF3',
    fontFamily: "'Plus Jakarta Sans', sans-serif",
  },
  card: {
    maxWidth: 440,
    padding: '48px 40px',
    background: '#161B22',
    borderRadius: 16,
    border: '1px solid #30363D',
    textAlign: 'center',
  },
  icon: {
    fontSize: 48,
    marginBottom: 16,
  },
  title: {
    fontSize: 20,
    fontWeight: 700,
    marginBottom: 12,
  },
  text: {
    fontSize: 14,
    lineHeight: 1.6,
    color: '#8B949E',
    marginBottom: 24,
  },
  success: {
    color: '#3FB950',
  },
  error: {
    color: '#F85149',
  },
  closeBtn: {
    display: 'inline-block',
    padding: '10px 24px',
    background: '#58A6FF',
    color: '#fff',
    borderRadius: 8,
    border: 'none',
    fontSize: 14,
    fontWeight: 600,
    cursor: 'pointer',
    textDecoration: 'none',
  },
};

export default function TwitterCallbackPage() {
  usePageTitle('Twitter Connected');
  const [searchParams] = useSearchParams();
  const [status, setStatus] = useState('loading');

  const oauthToken = searchParams.get('oauth_token');
  const oauthVerifier = searchParams.get('oauth_verifier');

  useEffect(() => {
    // If we have OAuth params, we could call the backend to complete the flow.
    // For now (API-key based posting), just show success.
    if (oauthToken && oauthVerifier) {
      // Future: POST /api/auth/twitter/complete { oauth_token, oauth_verifier }
      setStatus('success');
    } else {
      // No OAuth params — user likely navigated here directly or callback succeeded
      setStatus('success');
    }
  }, [oauthToken, oauthVerifier]);

  return (
    <div style={S.page}>
      <div style={S.card}>
        {status === 'loading' && (
          <>
            <div style={S.icon}>...</div>
            <div style={S.title}>Connecting your X account...</div>
            <p style={S.text}>Please wait while we complete the authorization.</p>
          </>
        )}
        {status === 'success' && (
          <>
            <div style={{ ...S.icon, ...S.success }}>&#10003;</div>
            <div style={S.title}>X Account Connected</div>
            <p style={S.text}>
              Your X (Twitter) account has been successfully connected to Aura Alpha.
              You can close this window and return to your settings.
            </p>
            <a href="/profile" style={S.closeBtn}>Go to Settings</a>
          </>
        )}
        {status === 'error' && (
          <>
            <div style={{ ...S.icon, ...S.error }}>&#10007;</div>
            <div style={S.title}>Connection Failed</div>
            <p style={S.text}>
              We couldn't connect your X account. Please try again from your account settings.
            </p>
            <a href="/profile" style={S.closeBtn}>Back to Settings</a>
          </>
        )}
      </div>
    </div>
  );
}
